import Sidebar from '../components/Sidebar';
import mainImage from '../assets/mainpage.png';

function MainPage() {
  return (
    <div className="relative w-full min-h-screen bg-white overflow-hidden">
      {/* ✅ 전체 배경 이미지 (항상 보이도록 설정) */}
      <img
        src={mainImage}
        alt="배경"
        className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[80%] h-[80%] pointer-events-none"
      />

      {/* ✅ 페이지 내용 */}
      <div className="relative z-10 flex px-8 pt-12 items-start">
        {/* 사이드바 */}
        <Sidebar />

        {/* 오른쪽 메인 콘텐츠 */}
        <main className="flex-1 flex flex-col items-center justify-start min-h-[80vh] px-12 pt-8">
          {/* 상단 타이틀 */}
          <h2 className="text-sm text-blue-600 bg-blue-100 px-4 py-2 rounded mb-10">
            오늘의 부동산 관련 지식 한 줄 팝업
          </h2>

          {/* 카드 목록 */}
          <div className="space-y-6 w-full max-w-2xl">
            {[
              { title: '부동산 관련 정보 제공' },
              { title: '부동산 관련 퀴즈' },
              { title: '부동산 지원 정책' },
            ].map((item, idx) => (
              <div
                key={idx}
                className="w-full bg-white border border-blue-200 rounded-xl shadow px-6 py-5 flex items-center justify-between hover:shadow-md transition"
              >
                <span className="text-lg font-semibold text-gray-800">
                  {item.title}
                </span>
                <button className="px-4 py-2 bg-blue-600 text-white rounded-lg text-sm hover:bg-blue-700">
                  바로가기
                </button>
              </div>
            ))}
          </div>
        </main>
      </div>
    </div>
  );
}

export default MainPage;
